		return err
	}

	// Validate resolved IPs for redirect target
	if err := validateResolvedIPs(req.URL.Hostname()); err != nil {
		return err
	}

	return nil
}

func FetchURLPreview(ctx echo.Context) error {
	req := new(PreviewRequest)
	if err := ctx.Bind(req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid JSON"})
	}

	// Validate URL format
	parsedURL, err := url.Parse(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid URL format"})
	}

	// Validate URL structure
	if err := validateURL(parsedURL); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": err.Error()})
	}

	// Validate resolved IPs (SSRF protection)
	if err := validateResolvedIPs(parsedURL.Hostname()); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": err.Error()})
	}

	// Create HTTP client with SSRF protections
	transport := &http.Transport{
		DialContext:     safeDialContext,
		TLSClientConfig: nil, // Use default TLS config
	}

