	}

	title, description := extractTitleAndDescription(body)

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

func extractTitleAndDescription(htmlContent []byte) (string, string) {
	// Simple extraction - in production, use a proper HTML parser
	content := string(htmlContent)

	var title, description string

	// Extract title
	if start := strings.Index(strings.ToLower(content), "<title>"); start != -1 {
		start += 7
		if end := strings.Index(strings.ToLower(content[start:]), "</title>"); end != -1 {
			title = strings.TrimSpace(content[start : start+end])
		}
	}

	// Extract meta description
	descPattern := `<meta name="description" content="`
	if start := strings.Index(strings.ToLower(content), strings.ToLower(descPattern)); start != -1 {
		start += len(descPattern)
		if end := strings.Index(content[start:], `"`); end != -1 {
			description = strings.TrimSpace(content[start : start+end])
		}
	}

	return title, description
