// isPrivateIP checks if an IP address is private/internal
func isPrivateIP(ip net.IP) bool {
	if ip == nil {
		return false
	}

	// Handle IPv4-mapped IPv6 addresses by converting to IPv4
	if ip4 := ip.To4(); ip4 != nil {
		ip = ip4
	}

	// Loopback
	if ip.IsLoopback() {
		return true
	}

	// Private networks (RFC 1918), link-local, multicast, reserved ranges
	privateCIDRs := []string{
		"10.0.0.0/8",
