		"255.255.255.255/32", // Broadcast
		"::1/128",        // IPv6 loopback
		"fc00::/7",       // IPv6 ULA
		"fe80::/10",      // IPv6 link-local
	}

	for _, cidr := range privateCIDRs {
		_, network, err := net.ParseCIDR(cidr)
		if err != nil {
			continue
		}
		if network.Contains(ip) {
			return true
		}
	}

	return false
}

// validateHost validates if a host can be accessed
func validateHost(hostname string) error {
	// Block known internal hostnames
	lowerHost := strings.ToLower(hostname)
	internalHosts := []string{"localhost", "localhost.localdomain", "local", "internal", "metadata.google.internal", "metadata"}
	for _, internal := range internalHosts {
		if lowerHost == internal || strings.HasSuffix(lowerHost, "."+internal) {
			return fmt.Errorf("access to internal resources is not allowed")
		}
	}

	// If hostname is an IP, validate it directly
	if ip := net.ParseIP(hostname); ip != nil {
		if isPrivateIP(ip) {
			return fmt.Errorf("access to internal resources is not allowed")
		}
		return nil
	}

	// Resolve hostname and validate all IPs
	ips, err := net.LookupIP(hostname)
	if err != nil {
		return fmt.Errorf("failed to resolve hostname")
	}

	for _, ip := range ips {
		if isPrivateIP(ip) {
			return fmt.Errorf("access to internal resources is not allowed")
		}
	}

	return nil
}

func FetchURLPreview(ctx echo.Context) error {
	req := new(PreviewRequest)
	if err := ctx.Bind(req); err != nil {
