	ip := net.ParseIP(hostname)
	if ip != nil {
		if isBlockedIP(ip) {
			return fmt.Errorf("access to private/blocked IP is not allowed")
		}
		return nil
	}

	// Resolve the hostname and check all IPs
	ips, err := net.LookupIP(hostname)
	if err != nil {
		return fmt.Errorf("failed to resolve hostname: %v", err)
