// safeDialContext is a custom dialer that blocks connections to private IPs
func safeDialContext(ctx context.Context, network, addr string) (net.Conn, error) {
	host, port, err := net.SplitHostPort(addr)
	if err != nil {
		return nil, err
	}

	// Check if host is an IP address
	ip := net.ParseIP(host)
	if ip != nil {
		if isBlockedIP(ip) {
			return nil, fmt.Errorf("connection to private/blocked IP is not allowed")
		}
