			Error: "URL is required",
		})
	}

	// Validate URL before making request
	err := validateURL(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, PreviewResponse{
			URL:   req.URL,
			Error: fmt.Sprintf("Invalid or blocked URL: %v", err),
		})
	}

	// Create HTTP request
	httpReq, err := http.NewRequest(http.MethodGet, req.URL, nil)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, PreviewResponse{
			URL:   req.URL,
			Error: fmt.Sprintf("Invalid URL: %v", err),
		})
	}

	// Set User-Agent header
	httpReq.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreview/1.0)")

