	resp, err := safeHTTPClient.Do(httpReq)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, PreviewResponse{
			URL:   req.URL,
			Error: fmt.Sprintf("Failed to fetch URL: %v", err),
		})
	}
