	// Check for loopback
	if ip.IsLoopback() {
		return true
	}

	// Check for unspecified (0.0.0.0, ::)
	if ip.IsUnspecified() {
		return true
	}

	// Check for IPv4 addresses
	if len(ip) == 4 {
		// 0.0.0.0/8 (current network)
		if ip[0] == 0 {
			return true
		}
		// 10.0.0.0/8 (private)
		if ip[0] == 10 {
			return true
		}
		// 127.0.0.0/8 (loopback)
		if ip[0] == 127 {
			return true
		}
		// 169.254.0.0/16 (link-local)
		if ip[0] == 169 && ip[1] == 254 {
			return true
		}
		// 172.16.0.0/12 (private)
		if ip[0] == 172 && ip[1] >= 16 && ip[1] <= 31 {
			return true
		}
		// 192.168.0.0/16 (private)
		if ip[0] == 192 && ip[1] == 168 {
			return true
		}
	} else if len(ip) == 16 {
		// IPv6
		// ::1 (loopback)
		if ip.IsLoopback() {
			return true
		}
		// fe80::/10 (link-local)
		if ip[0] == 0xfe && (ip[1]&0xc0) == 0x80 {
			return true
		}
		// fc00::/7 (unique local, private)
		if (ip[0] & 0xfe) == 0xfc {
			return true
		}
	}

	return false
}

// resolveAndValidateHost resolves a hostname and validates all IPs
func resolveAndValidateHost(hostname string) ([]net.IP, error) {
	// First check if it's already an IP address
	ip := net.ParseIP(hostname)
	if ip != nil {
		if isBlockedIP(ip) {
			return nil, fmt.Errorf("blocked IP address")
		}
		return []net.IP{ip}, nil
	}

	// Resolve hostname
	ips, err := net.LookupIP(hostname)
	if err != nil {
		return nil, err
	}

	if len(ips) == 0 {
		return nil, fmt.Errorf("no IPs found for hostname")
	}

	// Check all resolved IPs
	for _, ip := range ips {
		if isBlockedIP(ip) {
			return nil, fmt.Errorf("hostname resolves to blocked IP")
		}
	}

	return ips, nil
}

func FetchURLPreview(ctx echo.Context) error {
	var req PreviewRequest
	if err := ctx.Bind(&req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "invalid request body"})
	}

	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "url is required"})
	}

	// Parse URL
	parsedURL, err := url.Parse(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "invalid url"})
	}

	// Only allow http and https schemes
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "invalid scheme"})
	}

	// Get hostname
	hostname := parsedURL.Hostname()
	if hostname == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "empty hostname"})
	}

	// Resolve and validate hostname
	resolvedIPs, err := resolveAndValidateHost(hostname)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "blocked url"})
	}

	// Create context with 3 second timeout
	httpCtx, cancel := context.WithTimeout(context.Background(), 3*time.Second)
	defer cancel()

	// Create HTTP client with custom transport for SSRF protection
	// Use the resolved IP to avoid DNS rebinding
	dialer := &net.Dialer{
		Timeout:   10 * time.Second,
		KeepAlive: 10 * time.Second,
	}

	transport := &http.Transport{
		DialContext: func(ctx context.Context, network, addr string) (net.Conn, error) {
			host, port, err := net.SplitHostPort(addr)
			if err != nil {
				return nil, err
			}

			// Re-validate the host to ensure it matches our resolved IPs
			// This prevents DNS rebinding attacks
			var targetIPs []net.IP
			if host == hostname {
				targetIPs = resolvedIPs
			} else {
				// For redirects, resolve and validate again
				var err error
				targetIPs, err = resolveAndValidateHost(host)
				if err != nil {
					return nil, err
				}
			}

			// Use the first valid IP
			var targetIP net.IP
			for _, ip := range targetIPs {
				targetIP = ip
				break
			}

			if targetIP == nil {
				return nil, fmt.Errorf("no valid IP found")
			}

			return dialer.DialContext(ctx, network, net.JoinHostPort(targetIP.String(), port))
		},
	}

	client := &http.Client{
		Transport: transport,
		CheckRedirect: func(req *http.Request, via []*http.Request) error {
			// Validate redirect URL
			redirectHost := req.URL.Hostname()
			_, err := resolveAndValidateHost(redirectHost)
			if err != nil {
				return http.ErrUseLastResponse
			}
			return nil
		},
	}

	// Create HTTP request with timeout context
	httpReq, err := http.NewRequestWithContext(httpCtx, http.MethodGet, parsedURL.String(), nil)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "invalid url"})
	}

	// Set User-Agent header
	httpReq.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreview/1.0)")

	resp, err := client.Do(httpReq)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "failed to fetch url"})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "failed to fetch url: non-200 status"})
	}

	// Parse HTML
	doc, err := html.Parse(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "failed to parse html"})
	}

	// Extract title and description
	title := extractTitle(doc)
	description := extractDescription(doc)

	response := PreviewResponse{
		URL:         req.URL,
		Title:       title,
		Description: description,
	}

	return ctx.JSON(http.StatusOK, response)
}

func extractTitle(n *html.Node) string {
	if n.Type == html.ElementNode && n.Data == "title" {
		if n.FirstChild != nil {
			return n.FirstChild.Data
		}
		return ""
	}

	for c := n.FirstChild; c != nil; c = c.NextSibling {
		if title := extractTitle(c); title != "" {
			return title
		}
	}

	return ""
}

func extractDescription(n *html.Node) string {
	if n.Type == html.ElementNode && n.Data == "meta" {
		name := ""
		content := ""
		for _, attr := range n.Attr {
			if attr.Key == "name" {
				name = attr.Val
			}
			if attr.Key == "content" {
				content = attr.Val
			}
		}
		if name == "description" {
			return content
		}
	}

	for c := n.FirstChild; c != nil; c = c.NextSibling {
		if desc := extractDescription(c); desc != "" {
			return desc
		}
	}

	return ""
}

func main() {
	e := echo.New()
	e.POST("/preview", FetchURLPreview)
	e.Logger.Fatal(e.Start(":8080"))
}

