func validateURL(rawURL string) error {
	parsedURL, err := url.Parse(rawURL)
	if err != nil {
		return fmt.Errorf("invalid URL format")
	}

	// Only allow http and https schemes
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return fmt.Errorf("only http and https schemes are allowed")
	}

	// Extract hostname
	hostname := parsedURL.Hostname()
	if hostname == "" {
		return fmt.Errorf("invalid hostname")
	}

	// Check if hostname is "localhost" or ends with ".localhost"
	if hostname == "localhost" || strings.HasSuffix(hostname, ".localhost") {
		return fmt.Errorf("access to localhost is blocked")
	}

	// Try to parse as IP directly
	ip := net.ParseIP(hostname)
	if ip != nil {
		if isPrivateIP(ip) {
			return fmt.Errorf("access to private IP is blocked")
		}
		return nil
	}

	// Resolve the hostname and check all IPs
	addrs, err := net.LookupHost(hostname)
	if err != nil {
		return fmt.Errorf("failed to resolve hostname")
	}

	for _, addr := range addrs {
