	if err != nil {
		return ctx.JSON(http.StatusBadRequest, ErrorResponse{Error: "invalid url"})
	}

	// Set User-Agent header
	httpReq.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreviewBot/1.0)")

	resp, err := client.Do(httpReq)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, ErrorResponse{Error: "failed to fetch url"})
	}
	defer resp.Body.Close()

	// Parse HTML
	doc, err := html.Parse(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, ErrorResponse{Error: "failed to parse html"})
	}

	title := ""
	description := ""

	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode {
			if n.Data == "title" {
				title = extractText(n)
			} else if n.Data == "meta" {
				name := ""
				content := ""
				for _, attr := range n.Attr {
					if attr.Key == "name" {
						name = attr.Val
					} else if attr.Key == "content" {
						content = attr.Val
					}
				}
				if name == "description" {
					description = content
				}
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}

	traverse(doc)

	// Clean up title
	title = strings.TrimSpace(title)

	response := PreviewResponse{
		URL:         req.URL,
		Title:       title,
		Description: description,
	}

	return ctx.JSON(http.StatusOK, response)
