func isPrivateIP(ip net.IP) bool {
	if ip == nil {
		return false
	}

	// Convert IPv4-mapped IPv6 addresses to IPv4
	if ip.To4() != nil {
		ip = ip.To4()
	}

	// Check if it's a loopback address
	if ip.IsLoopback() {
