	}

	// Check if it's a private network
	if ip.IsPrivate() {
		return true
	}

	// Check for link-local addresses (169.254.0.0/16)
	if ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
		return true
	}

	// Check for unspecified address (0.0.0.0, ::)
	if ip.IsUnspecified() {
		return true
	}

	return false
}

