// validateURL validates that the URL is safe to fetch
func validateURL(rawURL string) (*url.URL, error) {
	parsedURL, err := url.Parse(rawURL)
	if err != nil {
		return nil, fmt.Errorf("invalid URL format")
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return nil, fmt.Errorf("only HTTP/HTTPS URLs are allowed")
	}

	hostname := parsedURL.Hostname()
	if hostname == "" {
		return nil, fmt.Errorf("invalid hostname")
	}

	// Check if hostname is an IP address
	ip := net.ParseIP(hostname)
	if ip != nil {
		if isPrivateIP(ip) {
			return nil, fmt.Errorf("access to private/restricted IP addresses is not allowed")
		}
	} else {
		// Check for known bypass hostnames
		lowerHostname := strings.ToLower(hostname)
		blockedHosts := []string{"localhost", "localtest.me", "metadata.google.internal", "169.254.169.254"}
		for _, blocked := range blockedHosts {
			if lowerHostname == blocked || strings.HasSuffix(lowerHostname, "."+blocked) {
				return nil, fmt.Errorf("access to restricted hostname is not allowed")
			}
		}
	}

	return parsedURL, nil
}

// safeDialContext creates a dial context that validates the resolved IP
func safeDialContext(ctx context.Context, network, addr string) (net.Conn, error) {
	host, port, err := net.SplitHostPort(addr)
	if err != nil {
		return nil, err
	}

	// Resolve the IP
	ips, err := net.DefaultResolver.LookupIPAddr(ctx, host)
	if err != nil {
		return nil, err
	}

	// Check all resolved IPs and find a valid one
	var validIP net.IP
	for _, ipAddr := range ips {
		if !isPrivateIP(ipAddr.IP) {
			validIP = ipAddr.IP
			break
		}
	}

	if validIP == nil {
		return nil, fmt.Errorf("access to private/restricted IP addresses is not allowed")
	}

	// Connect using the validated IP
	dialer := &net.Dialer{}
	return dialer.DialContext(ctx, network, net.JoinHostPort(validIP.String(), port))
}

// checkRedirect validates redirect URLs
func checkRedirect(req *http.Request, via []*http.Request) error {
	if len(via) >= 10 {
		return fmt.Errorf("too many redirects")
	}

	_, err := validateURL(req.URL.String())
	if err != nil {
		return err
	}

	return nil
}

func FetchURLPreview(ctx echo.Context) error {
	req := new(PreviewRequest)
	if err := ctx.Bind(req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid JSON"})
	}

	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "URL is required"})
	}

	parsedURL, err := validateURL(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": err.Error()})
	}

	transport := &http.Transport{
		DialContext:           safeDialContext,
		DisableKeepAlives:     true,
		ResponseHeaderTimeout: 5 * time.Second,
		TLSHandshakeTimeout:   5 * time.Second,
	}

	client := &http.Client{
		Timeout:       10 * time.Second,
		Transport:     transport,
		CheckRedirect: checkRedirect,
	}

	httpReq, err := http.NewRequest(http.MethodGet, parsedURL.String(), nil)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to create request"})
	}
	httpReq.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreviewBot/1.0)")

	resp, err := client.Do(httpReq)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to fetch URL"})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": fmt.Sprintf("HTTP %d", resp.StatusCode)})
	}

	body, err := io.ReadAll(io.LimitReader(resp.Body, 1024*1024))
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to read response body"})
	}

	title, description := extractTitleAndDescription(body)

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

func extractTitleAndDescription(htmlContent []byte) (string, string) {
	doc, err := html.Parse(strings.NewReader(string(htmlContent)))
	if err != nil {
		return "", ""
	}

	var title, description string

	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode {
			if n.Data == "title" && n.FirstChild != nil {
				title = n.FirstChild.Data
			} else if n.Data == "meta" {
				name := ""
				content := ""
				for _, attr := range n.Attr {
					switch attr.Key {
					case "name":
						name = attr.Val
					case "content":
						content = attr.Val
					}
				}
				if name == "description" {
					description = content
				}
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}
	traverse(doc)

	return strings.TrimSpace(title), strings.TrimSpace(description)
}

func main() {
	e := echo.New()
	e.POST("/preview", FetchURLPreview)
	e.Start(":8080")
}

