			if err := validateHost(req.URL.Host); err != nil {
				return fmt.Errorf("redirect to forbidden host: %w", err)
			}
			// Limit number of redirects
			if len(via) >= 5 {
				return fmt.Errorf("too many redirects")
			}
			return nil
		},
	}

