	for _, block := range privateBlocks {
		_, cidr, _ := net.ParseCIDR(block)
		if cidr.Contains(ip) {
			return true
		}
	}

	return false
}

// safeDialContext creates a safe dialer that validates IPs
func safeDialContext(ctx context.Context, network, addr string) (net.Conn, error) {
	host, port, err := net.SplitHostPort(addr)
	if err != nil {
		return nil, err
	}

	// Handle IPv6 addresses in brackets
	host = strings.TrimPrefix(host, "[")
	host = strings.TrimSuffix(host, "]")

	// Check if host is an IP address directly
	if ip := net.ParseIP(host); ip != nil {
		if isPrivateIP(ip) {
			return nil, fmt.Errorf("access to private IP %s is blocked", ip.String())
		}
		dialer := &net.Dialer{
			Timeout:   10 * time.Second,
			KeepAlive: 10 * time.Second,
		}
		return dialer.DialContext(ctx, network, addr)
	}

	// Check for blocked hostnames
	blockedHosts := []string{"localhost", "localtest.me"}
	for _, blocked := range blockedHosts {
		if strings.EqualFold(host, blocked) {
			return nil, fmt.Errorf("access to %s is blocked", host)
		}
	}

	// Resolve the host to IPs
	ips, err := net.DefaultResolver.LookupIPAddr(ctx, host)
	if err != nil {
		return nil, err
	}

	// Check all resolved IPs
	for _, ipAddr := range ips {
		if isPrivateIP(ipAddr.IP) {
			return nil, fmt.Errorf("access to private IP %s is blocked", ipAddr.IP.String())
		}
	}

	// Use the first valid IP to prevent DNS rebinding
	if len(ips) == 0 {
		return nil, fmt.Errorf("no IPs resolved for host %s", host)
	}

	dialer := &net.Dialer{
		Timeout:   10 * time.Second,
		KeepAlive: 10 * time.Second,
	}

	// Use the first IP to connect (prevents DNS rebinding)
	targetAddr := net.JoinHostPort(ips[0].IP.String(), port)
	return dialer.DialContext(ctx, network, targetAddr)
}

// checkRedirect validates redirect URLs
func checkRedirect(req *http.Request, via []*http.Request) error {
	if len(via) >= 10 {
		return fmt.Errorf("too many redirects")
	}

	// Validate the redirect URL
	parsedURL := req.URL

	// Only allow http and https schemes
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return fmt.Errorf("only http and https protocols are allowed for redirects")
	}

	// Extract hostname
	hostname := parsedURL.Hostname()
	if hostname == "" {
		return fmt.Errorf("invalid hostname in redirect")
	}

	// Handle IPv6 addresses in brackets
	hostname = strings.TrimPrefix(hostname, "[")
	hostname = strings.TrimSuffix(hostname, "]")

	// Check for blocked hostnames
	blockedHosts := []string{"localhost", "localtest.me", "0.0.0.0"}
	for _, blocked := range blockedHosts {
		if strings.EqualFold(hostname, blocked) {
			return fmt.Errorf("redirect to %s is blocked", hostname)
		}
	}

	// Check if hostname is an IP address
	if ip := net.ParseIP(hostname); ip != nil {
		if isPrivateIP(ip) {
			return fmt.Errorf("redirect to private IP %s is blocked", ip.String())
		}
		return nil
	}

	// Resolve and check IPs
	ips, err := net.LookupIP(hostname)
	if err != nil {
		return fmt.Errorf("failed to resolve redirect hostname: %v", err)
	}

	for _, ip := range ips {
		if isPrivateIP(ip) {
			return fmt.Errorf("redirect to private IP %s is blocked", ip.String())
		}
	}

	return nil
}

func FetchURLPreview(ctx echo.Context) error {
	var req PreviewRequest
	if err := ctx.Bind(&req); err != nil {
		return ctx.JSON(http.StatusBadRequest, PreviewResponse{
			Error: "Invalid request body",
		})
	}

	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, PreviewResponse{
			Error: "URL is required",
		})
	}

	// Parse and validate URL
	parsedURL, err := url.Parse(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, PreviewResponse{
			URL:   req.URL,
			Error: fmt.Sprintf("Invalid URL: %v", err),
		})
	}

	// Only allow http and https schemes
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.JSON(http.StatusBadRequest, PreviewResponse{
			URL:   req.URL,
			Error: "Only http and https protocols are allowed",
		})
	}

	// Extract hostname
	hostname := parsedURL.Hostname()
	if hostname == "" {
		return ctx.JSON(http.StatusBadRequest, PreviewResponse{
			URL:   req.URL,
			Error: "Invalid hostname",
		})
	}

	// Handle IPv6 addresses in brackets
	hostname = strings.TrimPrefix(hostname, "[")
	hostname = strings.TrimSuffix(hostname, "]")

	// Check for blocked hostnames
	blockedHosts := []string{"localhost", "localtest.me", "0.0.0.0"}
	for _, blocked := range blockedHosts {
		if strings.EqualFold(hostname, blocked) {
			return ctx.JSON(http.StatusForbidden, PreviewResponse{
				URL:   req.URL,
				Error: fmt.Sprintf("Access to %s is blocked", hostname),
			})
		}
	}

	// Check if hostname is an IP address directly
	if ip := net.ParseIP(hostname); ip != nil {
		if isPrivateIP(ip) {
			return ctx.JSON(http.StatusForbidden, PreviewResponse{
				URL:   req.URL,
				Error: fmt.Sprintf("Access to private IP %s is blocked", ip.String()),
			})
		}
	} else {
		// Resolve hostname and check IPs
		ips, err := net.LookupIP(hostname)
		if err != nil {
			return ctx.JSON(http.StatusBadGateway, PreviewResponse{
				URL:   req.URL,
				Error: fmt.Sprintf("Failed to resolve hostname: %v", err),
			})
		}

		for _, ip := range ips {
			if isPrivateIP(ip) {
				return ctx.JSON(http.StatusForbidden, PreviewResponse{
					URL:   req.URL,
					Error: fmt.Sprintf("Access to private IP %s is blocked", ip.String()),
				})
			}
		}
	}

	// Create context with 10 second timeout
	reqCtx, cancel := context.WithTimeout(context.Background(), 10*time.Second)
	defer cancel()

	// Create HTTP request with context
	httpReq, err := http.NewRequestWithContext(reqCtx, http.MethodGet, req.URL, nil)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, PreviewResponse{
			URL:   req.URL,
			Error: fmt.Sprintf("Failed to create request: %v", err),
		})
	}

	// Set User-Agent header
	httpReq.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreviewBot/1.0)")

	// Create safe HTTP client with custom transport
	transport := &http.Transport{
		DialContext: safeDialContext,
	}

	client := &http.Client{
		Transport:     transport,
		CheckRedirect: checkRedirect,
		Timeout:       30 * time.Second,
	}

	resp, err := client.Do(httpReq)
	if err != nil {
		return ctx.JSON(http.StatusBadGateway, PreviewResponse{
			URL:   req.URL,
			Error: fmt.Sprintf("Failed to fetch URL: %v", err),
		})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusBadGateway, PreviewResponse{
			URL:   req.URL,
			Error: fmt.Sprintf("HTTP error: %d", resp.StatusCode),
		})
	}

	// Read body
	body, err := io.ReadAll(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, PreviewResponse{
			URL:   req.URL,
			Error: fmt.Sprintf("Failed to read response body: %v", err),
		})
	}

	// Parse HTML
	title, description := extractMetadata(string(body))

	return ctx.JSON(http.StatusOK, PreviewResponse{
		URL:         req.URL,
		Title:       strings.TrimSpace(title),
		Description: strings.TrimSpace(description),
	})
}

func extractMetadata(htmlContent string) (title string, description string) {
	doc, err := html.Parse(strings.NewReader(htmlContent))
	if err != nil {
		return "", ""
	}

	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode {
			// Extract title from <title> tag
			if n.Data == "title" && n.FirstChild != nil {
				if title == "" {
					title = n.FirstChild.Data
				}
			}
			// Extract meta tags
			if n.Data == "meta" {
				name := ""
				content := ""
				property := ""
				for _, attr := range n.Attr {
					switch attr.Key {
					case "name":
						name = attr.Val
					case "content":
						content = attr.Val
					case "property":
						property = attr.Val
					}
				}
				// Standard meta description
				if name == "description" && description == "" {
					description = content
				}
				// Open Graph description
				if property == "og:description" && description == "" {
					description = content
				}
				// Open Graph title
				if property == "og:title" && title == "" {
					title = content
				}
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}
	traverse(doc)

	return title, description
}

func main() {
	e := echo.New()
	e.POST("/preview", FetchURLPreview)
	e.Logger.Fatal(e.Start(":8080"))
}

