			ips, err := resolveAndValidateIP(req.Context(), host)
			if err != nil {
				return errBlockedIP
			}

			if findValidIP(ips) == nil {
				return errBlockedIP
			}

			if len(via) >= 10 {
				return fmt.Errorf("too many redirects")
			}

			return nil
		},
	}

	resp, err := client.Do(httpReq)
	if err != nil {
		if err == errBlockedIP || strings.Contains(err.Error(), errBlockedIP.Error()) {
			return ctx.JSON(http.StatusOK, PreviewResponse{
				URL:   req.URL,
				Error: "Access to private/internal IPs is blocked",
			})
		}
		return ctx.JSON(http.StatusOK, PreviewResponse{
			URL:   req.URL,
			Error: fmt.Sprintf("Failed to fetch URL: %v", err),
		})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusOK, PreviewResponse{
			URL:   req.URL,
			Error: fmt.Sprintf("HTTP error: %d", resp.StatusCode),
		})
	}

	// Read body
	body, err := io.ReadAll(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusOK, PreviewResponse{
			URL:   req.URL,
			Error: fmt.Sprintf("Failed to read response: %v", err),
		})
	}

	// Parse HTML
	title, description := extractMetadata(string(body))

	return ctx.JSON(http.StatusOK, PreviewResponse{
		URL:         req.URL,
		Title:       strings.TrimSpace(title),
		Description: strings.TrimSpace(description),
	})
}

func extractMetadata(htmlContent string) (title, description string) {
	doc, err := html.Parse(strings.NewReader(htmlContent))
	if err != nil {
		return "", ""
	}

	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode {
			if n.Data == "title" && n.FirstChild != nil && title == "" {
				title = extractTextContent(n)
			} else if n.Data == "meta" && description == "" {
				name := ""
				property := ""
				content := ""
				for _, attr := range n.Attr {
					switch attr.Key {
					case "name":
						name = attr.Val
					case "property":
						property = attr.Val
					case "content":
						content = attr.Val
					}
				}
				if name == "description" || property == "og:description" {
					description = content
				}
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}

	traverse(doc)
	return title, description
}

func extractTextContent(n *html.Node) string {
	if n.Type == html.TextNode {
		return n.Data
	}
	var result string
	for c := n.FirstChild; c != nil; c = c.NextSibling {
		result += extractTextContent(c)
	}
	return result
}

func main() {
	e := echo.New()
	e.POST("/preview", FetchURLPreview)
	e.Logger.Fatal(e.Start(":8080"))
}

