	defer cancel()

	httpReq, err := http.NewRequestWithContext(reqCtx, "GET", req.URL, nil)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, PreviewResponse{
			URL:   req.URL,
			Error: fmt.Sprintf("Failed to create request: %v", err),
		})
	}

	httpReq.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreview/1.0)")

	resp, err := client.Do(httpReq)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, PreviewResponse{
			URL:   req.URL,
			Error: fmt.Sprintf("Failed to fetch URL: %v", err),
		})
